import{_ as e}from"./chunks/Gemini_Generated_Image_fug6l2fug6l2fug6.wlNFePn-.js";import{_ as o,o as r,c as t,ag as i}from"./chunks/framework.BZohXCq9.js";const b=JSON.parse('{"title":"What Is Bamdra","description":"Bamdra builds scenario-driven AI applications. Learn the brand story behind the bamboo dragonfly and the product philosophy guiding our work.","frontmatter":{"title":"What Is Bamdra","description":"Bamdra builds scenario-driven AI applications. Learn the brand story behind the bamboo dragonfly and the product philosophy guiding our work."},"headers":[],"relativePath":"guide/what-is-bamdra.md","filePath":"guide/what-is-bamdra.md","lastUpdated":null}'),n={name:"guide/what-is-bamdra.md"};function s(d,a,l,h,c,m){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="what-is-bamdra" tabindex="-1">What Is Bamdra <a class="header-anchor" href="#what-is-bamdra" aria-label="Permalink to &quot;What Is Bamdra&quot;">​</a></h1><figure class="doc-figure doc-parallax"><img src="'+e+'" alt="Bamdra brand cover"><figcaption>Bamdra stands for AI that takes flight from human intent and returns with practical value.</figcaption></figure><h2 id="a-vision-for-ai-in-real-work" tabindex="-1">A vision for AI in real work <a class="header-anchor" href="#a-vision-for-ai-in-real-work" aria-label="Permalink to &quot;A vision for AI in real work&quot;">​</a></h2><p>Bamdra is about a simple ambition: AI should not remain on the edge of work. It should enter the places where people actually spend time, carry context across interruptions, reduce repetition, and help reshape the structure of everyday collaboration.</p><h2 id="why-the-name-means-something" tabindex="-1">Why the name means something <a class="header-anchor" href="#why-the-name-means-something" aria-label="Permalink to &quot;Why the name means something&quot;">​</a></h2><p>Bamdra is derived from &quot;bamboo dragonfly&quot;. A bamboo dragonfly rises because human hands launch it. Once in the air, it can see farther and travel beyond the reach of the hand alone. Yet it ultimately belongs back in human hands. That is our view of AI systems:</p><ul><li>human intent gives them purpose</li><li>machine capability extends their reach</li><li>human judgment remains the final owner of direction and responsibility</li></ul><h2 id="product-philosophy" tabindex="-1">Product philosophy <a class="header-anchor" href="#product-philosophy" aria-label="Permalink to &quot;Product philosophy&quot;">​</a></h2><h3 id="build-for-actual-workflows" tabindex="-1">Build for actual workflows <a class="header-anchor" href="#build-for-actual-workflows" aria-label="Permalink to &quot;Build for actual workflows&quot;">​</a></h3><p>We design for operations, delivery, engineering, and knowledge work where one conversation can contain many threads and where context continuity matters.</p><h3 id="keep-intelligence-accountable" tabindex="-1">Keep intelligence accountable <a class="header-anchor" href="#keep-intelligence-accountable" aria-label="Permalink to &quot;Keep intelligence accountable&quot;">​</a></h3><p>AI should broaden perspective without making ownership ambiguous. Products must stay observable, controllable, and bounded by clear human decisions.</p><h3 id="change-workflows-not-just-demos" tabindex="-1">Change workflows, not just demos <a class="header-anchor" href="#change-workflows-not-just-demos" aria-label="Permalink to &quot;Change workflows, not just demos&quot;">​</a></h3><p>The real standard is not whether AI can perform a capability once. The real standard is whether it changes how people plan, resume, coordinate, remember, and make decisions over time.</p><h2 id="what-bamdra-is-building-now" tabindex="-1">What Bamdra is building now <a class="header-anchor" href="#what-bamdra-is-building-now" aria-label="Permalink to &quot;What Bamdra is building now&quot;">​</a></h2><p>Our first public product line is the Bamdra OpenClaw memory suite. Its main repository is <code>bamdra-openclaw-memory</code>, and it is joined by <code>bamdra-user-bind</code> and <code>bamdra-memory-vector</code>. Together they make long sessions more coherent, more durable, and easier to resume.</p>',16)])])}const f=o(n,[["render",s]]);export{b as __pageData,f as default};
